// Implicit Type Casting
int a = 10;
double b = a;  // Automatically converted
System.out.println(a); // 10
System.out.println(b); // 10.0

// Common Question
long a1 = 12L;
float d = a1;
System.out.println(a1); // 12
System.out.println(d);  // 12.0

// Explicit Type Casting
double d1 = 10.99;
int a2 = (int) d1;  // Manually cast double to int
System.out.println(a2); // 10 (decimal part lost)

