// if-else Syntax
if (condition) {
    // Executes if condition is true
} else {
    // Executes if condition is false
}

// if-else Example
int age = 18;
if (age >= 18) {
    System.out.println("Eligible to vote");
} else {
    System.out.println("Not eligible to vote");
}

// else-if Ladder Syntax
if (condition1) {
    // block1
} else if (condition2) {
    // block2
} else {
    // blockN
}

// else-if Example
int marks = 85;

if (marks >= 90) {
    System.out.println("Grade A");
} else if (marks >= 75) {
    System.out.println("Grade B");
} else if (marks >= 60) {
    System.out.println("Grade C");
} else {
    System.out.println("Fail");
}


// switch Syntax
switch(expression) {
    case value1:
        // code
        break;
    case value2:
        // code
        break;
    ...
    default:
        // default code
        break;
}

// switch Example
int day = 2;
switch(day) {
    case 1: System.out.println("Monday"); break;
    case 2: System.out.println("Tuesday"); break;
    default: System.out.println("Invalid Day"); break;
}

// for Loop Syntax
for (initialization; condition; update) {
    // loop body
}

// for Example
for (int i = 1; i <= 5; i++) {
    System.out.println(i);
}

// Infinite loop
for (;;) {
    // Infinite loop
}

// Multiple variable initialization
for (int i = 0, j = 10; i < j; i++, j--) {
    System.out.println(i + " " + j);
}

// while Syntax
while (condition) {
    // loop body
}

// while Example
int i = 1;
while (i <= 5) {
    System.out.println(i);
    i++;
}

// do-while Syntax
do {
    // loop body
} while (condition);

// do-while Example
int x = 1;
do {
    System.out.println(x);
    x++;
} while (x <= 5);

// break Example
for (int i = 1; i <= 10; i++) {
    if (i == 5) break;
    System.out.println(i);
}

// continue Example
for (int i = 1; i <= 5; i++) {
    if (i == 3) continue;
    System.out.println(i);
}

