// Abstract Class
abstract class Animal{
   abstract void makeSound();

   void sleep(){
      System.out.println("Sleeping...");
   }
}

class Dog extends Animal{
   void makeSound(){
      System.out.println("Dog barks!");
   }
}

class Main{
   public static void main(String[] args){
      Dog myDog = new Dog();
      myDog.makeSound();
      myDog.sleep();
   }
}

